 1	import type { FC } from 'react';
 2	import { useWatch } from 'react-hook-form';
 3	
 4	import ExpandableReviewSection from '@components/ExpandableReviewSection/ExpandableReviewSection';
 5	import {
 6	  DescriptionList,
 7	  DescriptionListDescription,
 8	  DescriptionListGroup,
 9	  DescriptionListTerm,
10	  useWizardContext,
11	} from '@patternfly/react-core';
12	
13	import { planStepNames, PlanWizardStepId } from '../../constants';
14	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
15	import { GeneralFormFieldId, generalFormFieldLabels } from '../general-information/constants';
16	
17	const GeneralInfoReviewSection: FC = () => {
18	  const { goToStepById } = useWizardContext();
19	  const { control } = useCreatePlanFormContext();
20	  const [planName, planProject, sourceProvider, targetProvider, targetProject] = useWatch({
21	    control,
22	    name: [
23	      GeneralFormFieldId.PlanName,
24	      GeneralFormFieldId.PlanProject,
25	      GeneralFormFieldId.SourceProvider,
26	      GeneralFormFieldId.TargetProvider,
27	      GeneralFormFieldId.TargetProject,
28	    ],
29	  });
30	
31	  return (
32	    <ExpandableReviewSection
33	      title={planStepNames[PlanWizardStepId.General]}
34	      testId="review-general-section"
35	      onEditClick={() => {
36	        goToStepById(PlanWizardStepId.General);
37	      }}
38	    >
39	      <DescriptionList isHorizontal horizontalTermWidthModifier={{ default: '18ch' }}>
40	        <DescriptionListGroup>
41	          <DescriptionListTerm>
42	            {generalFormFieldLabels[GeneralFormFieldId.PlanName]}
43	          </DescriptionListTerm>
44	
45	          <DescriptionListDescription data-testid="review-plan-name">
46	            {planName}
47	          </DescriptionListDescription>
48	        </DescriptionListGroup>
49	
50	        <DescriptionListGroup>
51	          <DescriptionListTerm>
52	            {generalFormFieldLabels[GeneralFormFieldId.PlanProject]}
53	          </DescriptionListTerm>
54	
55	          <DescriptionListDescription data-testid="review-plan-project">
56	            {planProject}
57	          </DescriptionListDescription>
58	        </DescriptionListGroup>
59	
60	        <DescriptionListGroup>
61	          <DescriptionListTerm>
62	            {generalFormFieldLabels[GeneralFormFieldId.SourceProvider]}
63	          </DescriptionListTerm>
64	
65	          <DescriptionListDescription data-testid="review-source-provider">
66	            {sourceProvider?.metadata?.name}
67	          </DescriptionListDescription>
68	        </DescriptionListGroup>
69	
70	        <DescriptionListGroup>
71	          <DescriptionListTerm>
72	            {generalFormFieldLabels[GeneralFormFieldId.TargetProvider]}
73	          </DescriptionListTerm>
74	
75	          <DescriptionListDescription data-testid="review-target-provider">
76	            {targetProvider?.metadata?.name}
77	          </DescriptionListDescription>
78	        </DescriptionListGroup>
79	
80	        <DescriptionListGroup>
81	          <DescriptionListTerm>
82	            {generalFormFieldLabels[GeneralFormFieldId.TargetProject]}
83	          </DescriptionListTerm>
84	
85	          <DescriptionListDescription data-testid="review-target-project">
86	            {targetProject}
87	          </DescriptionListDescription>
88	        </DescriptionListGroup>
89	      </DescriptionList>
90	    </ExpandableReviewSection>
91	  );
92	};
93	
94	export default GeneralInfoReviewSection;

